        public override async Task<Allocation> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Allocation>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<Allocation>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Allocation>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Shift.Name.Contains(search.Name)
                     || x.WeekOffSetup.Name.Contains(search.Name)
                     || x.WorkHoursSetting.Name.Contains(search.Name))
                     && x.EmployeeId == search.RefId.Value,
                include: i => i.Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Shift.Name", ascending: !search.IsDescend);
